      label: "Anthropic",
      docsPath: "/providers/models",
      envVars: ["ANTHROPIC_OAUTH_TOKEN", "ANTHROPIC_API_KEY"],
      auth: [...],
      // ... provider configuration
    });
    api.registerMediaUnderstandingProvider(anthropicMediaUnderstandingProvider);
  },
});
```

